## Tests

```typescript
// calculateDiscount.test.ts

import { calculateDiscount } from "./calculateDiscount";
import type { Customer } from "./types";

const BASE_NOW = new Date("2024-06-01T00:00:00Z");

function makeCustomer(overrides: Partial<Customer>): Customer {
  return {
    id: "test-customer",
    tier: "standard",
    accountCreatedAt: new Date("2024-01-01T00:00:00Z"), // 152 days before BASE_NOW
    lastPurchasedAt: null,
    ...overrides,
  };
}

// ─── AC1: New customer (<30 days) ────────────────────────────────────────────

describe("AC1 — new customer discount", () => {
  it("returns 5% when account is 1 day old", () => {
    const customer = makeCustomer({
      accountCreatedAt: new Date("2024-05-31T00:00:00Z"), // 1 day old
    });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0.05);
  });

  it("returns 5% when account is 29 days old (boundary)", () => {
    const customer = makeCustomer({
      accountCreatedAt: new Date("2024-05-03T00:00:00Z"), // 29 days old
    });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0.05);
  });

  it("does NOT return 5% when account is exactly 30 days old", () => {
    const customer = makeCustomer({
      accountCreatedAt: new Date("2024-05-02T00:00:00Z"), // exactly 30 days
    });
    expect(calculateDiscount(customer, BASE_NOW)).not.toBe(0.05);
  });
});

// ─── AC2: Returning customer, no recent purchase (win-back) ──────────────────

describe("AC2 — win-back rate", () => {
  it("returns 3% for returning customer with no purchase history", () => {
    const customer = makeCustomer({ lastPurchasedAt: null });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0.03);
  });

  it("returns 3% for returning customer whose last purchase was 91 days ago", () => {
    const customer = makeCustomer({
      lastPurchasedAt: new Date("2024-03-02T00:00:00Z"), // 91 days before BASE_NOW
    });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0.03);
  });

  it("returns 3% for returning customer whose last purchase was exactly 90 days ago (boundary — not within 90 days)", () => {
    const customer = makeCustomer({
      lastPurchasedAt: new Date("2024-03-03T00:00:00Z"), // exactly 90 days
    });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0.03);
  });
});

// ─── AC3: Active returning customer — no discount ────────────────────────────

describe("AC3 — no discount for active customers", () => {
  it("returns 0% for returning customer with purchase 1 day ago", () => {
    const customer = makeCustomer({
      lastPurchasedAt: new Date("2024-05-31T00:00:00Z"), // 1 day ago
    });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0);
  });

  it("returns 0% for returning customer with purchase 89 days ago (within 90-day window)", () => {
    const customer = makeCustomer({
      lastPurchasedAt: new Date("2024-03-04T00:00:00Z"), // 89 days ago
    });
    expect(calculateDiscount(customer, BASE_NOW)).toBe(0);
  });
});
```

